// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





// Place helper components here if needed

function getWeatherIcon(condition?: string) {
  const c = (condition || '').toLowerCase();
  if (c.includes('sun')) return { icon: '☀️', label: 'Sunny' };
  if (c.includes('rain')) return { icon: '🌧️', label: 'Rainy' };
  if (c.includes('cloud')) return { icon: '☁️', label: 'Cloudy' };
  if (c.includes('snow')) return { icon: '❄️', label: 'Snowy' };
  return { icon: '🌡️', label: 'Condition' };
}

export default function Component(props: Props) {
  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6)">
      <Card padding="var(--ggui-spacing-6)" shadow="lg" radius="xl">
        <Stack gap="var(--ggui-spacing-6)">
          <Row justify="between" align="center">
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={1}>{props.city}</Heading>
              <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant)">
                Current Weather
              </Text>
            </Stack>
            <Stack align="center" gap="var(--ggui-spacing-1)">
              <Text size="4xl" role="img" aria-label={getWeatherIcon(props.condition).label}>
                {getWeatherIcon(props.condition).icon}
              </Text>
              <Text variant="label">{props.condition}</Text>
            </Stack>
          </Row>

          <Box>
            <Text size="4xl" weight="bold">
              {props.temperature}°{props.unit}
            </Text>
          </Box>

          <Row gap="var(--ggui-spacing-6)">
            <Box>
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
              <Text variant="bodyLarge" weight="semibold">{props.humidity}%</Text>
            </Box>
            <Box>
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Wind Speed</Text>
              <Text variant="bodyLarge" weight="semibold">{props.windSpeed} km/h</Text>
            </Box>
          </Row>

          <Divider />

          <Stack gap="var(--ggui-spacing-3)">
            <Text variant="label">5-Day Forecast</Text>
            <Row justify="between" gap="var(--ggui-spacing-2)">
              {(props.forecast || []).map((day, index) => (
                <Box as={Hoverable} key={index} padding="var(--ggui-spacing-2)" radius="md">
                  <Stack align="center" gap="var(--ggui-spacing-2)">
                    <Text variant="label">{day.day}</Text>
                    <Text size="2xl" role="img" aria-label="Forecast icon">{day.icon || '🌡️'}</Text>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
