import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed

// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: 3,
    features: [] as string[],
    comments: '',
  });

  const isEmailValid = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const canGoNext = useMemo(() => {
    if (step === 1) return formData.name.trim() !== '' && isEmailValid(formData.email);
    return true;
  }, [step, formData.name, formData.email]);

  const updateField = (field: string, value: any) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
  };

  const toggleFeature = (feature: string) => {
    setFormData((prev) => ({
      ...prev,
      features: prev.features.includes(feature)
        ? prev.features.filter((f) => f !== feature)
        : [...prev.features, feature],
    }));
  };

  const handleSubmit = () => {
    submit({
      name: formData.name,
      email: formData.email,
      satisfaction: formData.satisfaction,
      features: formData.features,
      comments: formData.comments,
    });
  };

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={2}>Customer Survey</Heading>
          <Progress value={step} max={4} variant="default" />
          <Text variant="caption">Step {step} of 4</Text>
        </Stack>

        <Card padding="var(--ggui-spacing-6)">
          {step === 1 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Personal Information</Heading>
              <Input
                label="Name"
                value={formData.name}
                onChange={(v) => updateField('name', v)}
                required
              />
              <Input
                label="Email"
                type="email"
                value={formData.email}
                onChange={(v) => updateField('email', v)}
                error={formData.email && !isEmailValid(formData.email) ? 'Invalid email format' : undefined}
                required
              />
            </Stack>
          )}

          {step === 2 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Satisfaction Rating</Heading>
              <RadioGroup
                label="How satisfied are you?"
                value={String(formData.satisfaction)}
                onChange={(v) => updateField('satisfaction', parseInt(v))}
                options={[1, 2, 3, 4, 5].map((val) => ({
                  value: String(val),
                  label: props.satisfactionLabels[val - 1] || String(val),
                }))}
              />
            </Stack>
          )}

          {step === 3 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Additional Comments</Heading>
              <TextArea
                label="Any additional feedback?"
                value={formData.comments}
                onChange={(v) => updateField('comments', v)}
                maxLength={500}
              />
              <Text variant="caption">{formData.comments.length} / 500 characters</Text>
            </Stack>
          )}

          {step === 4 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Review</Heading>
              <Stack gap="var(--ggui-spacing-1)">
                <Text><strong>Name:</strong> {formData.name}</Text>
                <Text><strong>Email:</strong> {formData.email}</Text>
                <Text><strong>Satisfaction:</strong> {props.satisfactionLabels[formData.satisfaction - 1] || 'Not rated'}</Text>
                <Text><strong>Features:</strong> {formData.features.join(', ') || 'None'}</Text>
                <Text><strong>Comments:</strong> {formData.comments || 'No comments'}</Text>
              </Stack>
            </Stack>
          )}
        </Card>

        <Row gap="var(--ggui-spacing-4)" justify="between">
          <Button
            as={Clickable}
            variant="secondary"
            onClick={() => setStep((s) => Math.max(1, s - 1))}
            disabled={step === 1}
          >
            Back
          </Button>
          {step < 4 ? (
            <Button
              as={Clickable}
              variant="primary"
              onClick={() => setStep((s) => Math.min(4, s + 1))}
              disabled={!canGoNext}
            >
              Next
            </Button>
          ) : (
            <Button as={Clickable} variant="primary" onClick={handleSubmit}>
              Submit
            </Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}

