import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  const [taskList, setTaskList] = useState(props.tasks || []);
  const columns = props.columns || [];
  const [isAdding, setIsAdding] = useState<string | null>(null);
  const [draft, setDraft] = useState({ title: '', priority: 'medium' as 'low' | 'medium' | 'high' });

  useEffect(() => {
    if (taskChanged.latest) {
      const { action, task } = taskChanged.latest;
      if (action === 'delete') {
        setTaskList(prev => prev.filter(t => t.id !== task?.id));
      } else if (task) {
        setTaskList(prev => {
          const index = prev.findIndex(t => t.id === task.id);
          if (index !== -1) {
            const next = [...prev];
            next[index] = { ...next[index], ...task };
            return next;
          }
          return [...prev, task as any];
        });
      }
    }
  }, [taskChanged.latest]);

  const handleMove = (taskId: string, newColumn: string) => {
    setTaskList(prev => prev.map(t => t.id === taskId ? { ...t, column: newColumn } : t));
    taskUpdate({ action: 'move', taskId, data: { column: newColumn } });
  };

  const handleCreate = (columnId: string) => {
    if (!draft.title) return;
    const taskId = `temp-${Math.random().toString(36).substr(2, 9)}`;
    const newTask = { 
      id: taskId, 
      title: draft.title, 
      priority: draft.priority, 
      column: columnId, 
      assignee: 'Me' 
    };
    setTaskList(prev => [...prev, newTask]);
    taskUpdate({ action: 'create', taskId, data: { column: columnId } });
    setIsAdding(null);
    setDraft({ title: '', priority: 'medium' });
  };
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editTitle, setEditTitle] = useState('');

  const handleEdit = (task: typeof taskList[0]) => {
    if (!task.id) return;
    setTaskList(prev => prev.map(t => t.id === task.id ? { ...t, title: editTitle } : t));
    taskUpdate({ action: 'edit', taskId: task.id, data: { ...task, title: editTitle } as any });
    setEditingId(null);
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        <Row justify="between" align="end">
          <Stack gap="var(--ggui-spacing-1)">
            <Heading level={1}>Task Board</Heading>
            <Text color="var(--ggui-color-primary-600)">
            <Text color="var(--ggui-color-primary-600)">
              Managing {taskList.length} tasks across {columns.length} columns
            </Text>
          </Stack>
          <Badge variant="info" size="lg">
            {taskList.filter(t => t.column === 'done').length} / {taskList.length} Done
          </Badge>
        </Row>

        <Row gap="var(--ggui-spacing-6)" align="start" style={{ overflowX: 'auto', paddingBottom: 'var(--ggui-spacing-4)' }}>
          {columns.map(column => (
            <Stack key={column.id} gap="var(--ggui-spacing-4)" style={{ flex: '1 0 320px', minWidth: '320px' }}>
              <Box 
                padding="var(--ggui-spacing-3)" 
                background="var(--ggui-color-neutral-100)" 
                borderRadius="var(--ggui-shape-radius-md)"
              >
                <Row justify="between" align="center">
                  <Heading level={4}>{column.name}</Heading>
                  <Badge variant="default">
                    {taskList.filter(t => t.column === column.id).length}
                  </Badge>
                </Row>
              </Box>

              <Stack gap="var(--ggui-spacing-3)">
                {taskList
                  .filter(t => t.column === column.id)
                  .map(task => (
                    <Card key={task.id || Math.random().toString()} padding="var(--ggui-spacing-4)" shadow="md">
                      <Stack gap="var(--ggui-spacing-3)">
                        <Row justify="between" align="start">
                          {editingId === task.id ? (
                            <Stack gap="var(--ggui-spacing-1)">
                              <Input label="Edit Title" value={editTitle} onChange={setEditTitle} />
                              <Button variant="primary" size="xs" onClick={() => handleEdit(task)}>Save</Button>
                            </Stack>
                          ) : (
                            <Box as={Clickable} onClick={() => { setEditingId(task.id!); setEditTitle(task.title || ''); }}>
                              <Text weight="bold" size="base">{task.title}</Text>
                            </Box>
                          )}
                          <Badge 
                            variant={task.priority === 'high' ? 'error' : task.priority === 'medium' ? 'warning' : 'info'}
                          >
                            {task.priority}
                          </Badge>
                        </Row>

                        <Row gap="var(--ggui-spacing-3)" align="center">
                          {task.assignee && (
                            <Row gap="var(--ggui-spacing-2)" align="center">
                              <Avatar size="xs" name={task.assignee} />
                              <Text variant="caption">{task.assignee}</Text>
                            </Row>
                          )}
                          {task.dueDate && (
                            <Text variant="caption" color="var(--ggui-color-neutral-400)">
                              📅 {task.dueDate}
                            </Text>
                          )}
                        </Row>

                        <Divider />

                        <Row gap="var(--ggui-spacing-2)" wrap>
                          {columns
                            .filter(c => c.id && c.id !== column.id)
                            .map(c => (
                              <Box 
                                key={c.id} 
                                as={Clickable} 
                                onClick={() => task.id && handleMove(task.id, c.id!)}
                                aria-label={`Move task to ${c.name}`}
                              >
                                <Tag variant="info" size="sm">
                                  → {c.name}
                                </Tag>
                              </Box>
                            ))}
                        </Row>
                      </Stack>
                    </Card>
                  ))}
                        </Row>
                      </Stack>
                    </Card>
                  ))}

                {isAdding === column.id ? (
                  <Card padding="var(--ggui-spacing-4)" background="var(--ggui-color-neutral-50)">
                    <Stack gap="var(--ggui-spacing-4)">
                      <Input 
                        label="Task Title" 
                        value={draft.title} 
                        onChange={(v) => setDraft(d => ({ ...d, title: v }))}
                      />
                      <Select 
                        label="Priority" 
                        value={draft.priority} 
                        onChange={(v) => setDraft(d => ({ ...d, priority: v as any }))}
                        options={[
                          { label: 'Low', value: 'low' },
                          { label: 'Medium', value: 'medium' },
                          { label: 'High', value: 'high' }
                        ]}
                      />
                       <Row gap="var(--ggui-spacing-2)">
                          <Button variant="primary" as={Clickable} onClick={() => column.id && handleCreate(column.id)}>
                            Create
                          </Button>
                          <Button variant="ghost" as={Clickable} onClick={() => setIsAdding(null)}>
                            Cancel
                          </Button>
                        </Row>
                    </Stack>
                  </Card>
                ) : (
                  <Box as={Clickable} onClick={() => setIsAdding(column.id!)}>
                    <Button variant="outline" style={{ width: '100%' }}>
                      + Add Task
                    </Button>
                  </Box>
                )}
              </Stack>
            </Stack>
          ))}
        </Row>
      </Stack>
    </Container>
  );
}

