// Place helper components here if needed

const CATEGORY_COLORS: Record<string, string> = {
  'alkali-metal': 'var(--ggui-color-primary-300)',
  'alkaline-earth-metal': 'var(--ggui-color-primary-200)',
  'transition-metal': 'var(--ggui-color-primary-400)',
  'post-transition-metal': 'var(--ggui-color-primary-500)',
  'metalloid': 'var(--ggui-color-success-300)',
  'nonmetal': 'var(--ggui-color-success-400)',
  'halogen': 'var(--ggui-color-warning-300)',
  'noble-gas': 'var(--ggui-color-error-300)',
  'lanthanide': 'var(--ggui-color-info-300)',
  'actinide': 'var(--ggui-color-info-400)',
};

const DEFAULT_CATEGORY_COLOR = 'var(--ggui-color-surfaceVariant)';

function getCategoryColor(category?: string) {
  if (!category) return DEFAULT_CATEGORY_COLOR;
  const key = category.toLowerCase().replace(/ /g, '-');
  return CATEGORY_COLORS[key] || DEFAULT_CATEGORY_COLOR;
}

export default function Component(props: Props) {
