  const [selectedElement, setSelectedElement] = useState<typeof props.elements[0] | null>(null);

  const filteredElements = useMemo(() => {
    const term = searchTerm.toLowerCase();
    return (props.elements || []).filter(el => 
      el.name?.toLowerCase().includes(term) || 
      el.symbol?.toLowerCase().includes(term)
    );
  }, [searchTerm, props.elements]);

  const categories = useMemo(() => {
    const cats = new Set((props.elements || []).map(el => el.category || 'Unknown'));
    return Array.from(cats);
  }, [props.elements]);

