  const [typingSenders, setTypingSenders] = useState<Set<string>>(new Set());
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage');
  const messageStream = useStream<StreamMessage>('message');
  const typingStream = useStream<StreamTyping>('typing');

  useEffect(() => {
    if (messageStream.latest) {
      setMessages((prev) => [...prev, messageStream.latest!]);
    }
  }, [messageStream.latest]);

  useEffect(() => {
    if (typingStream.latest) {
      setTypingSenders((prev) => {
        const next = new Set(prev);
        if (typingStream.latest?.sender) {
          if (typingStream.latest.active) next.add(typingStream.latest.sender);
          else next.delete(typingStream.latest.sender);
        }
        return next;
      });
    }
  }, [typingStream.latest]);

