        </Box>

        <Box padding="var(--ggui-spacing-4)" style={{ flex: 1, overflowY: 'auto' }}>
          <Stack gap="var(--ggui-spacing-4)">
            {messages.map((m, i) => (
              <MessageBubble 
                key={i} 
                message={m} 
                isCurrentUser={m.sender === props.currentUser} 
                showSender={i === messages.length - 1 || messages[i + 1]?.sender !== m.sender} 
              />
            ))}

            <div ref={messagesEndRef} />
          </Stack>
        </Box>

        <Box padding="var(--ggui-spacing-4)" style={{ borderTop: '1px solid var(--ggui-color-outlineVariant)' }}>
          <Row gap="var(--ggui-spacing-2)">
            <Input
              label="Compose message"
              value={inputValue}
              onChange={setInputValue}
              placeholder="Type your message..."
              onKeyDown={(e: any) => e.key === 'Enter' && handleSend()}
              style={{ flex: 1 }}
            />
            <Button as={Clickable} disabled={!inputValue.trim()} onClick={handleSend} style={{ alignSelf: 'flex-end' }}>Send</Button>


          </Row>
