              <Text variant="label">Avatar Selection</Text>
              <Row gap="var(--ggui-spacing-2)">
                {(props.avatarOptions || []).map((emoji) => (
                  <Box key={emoji} as={Hoverable} onClick={() => setFormData({ ...formData, avatar: emoji })} padding="var(--ggui-spacing-2)" background={formData.avatar === emoji ? 'var(--ggui-color-primary-100)' : 'var(--ggui-color-surfaceVariant)'} borderRadius="var(--ggui-shape-radius-md)" border={formData.avatar === emoji ? '2px solid var(--ggui-color-primary-600)' : '2px solid transparent'} cursor="pointer">
                    <Text size="2xl">{emoji}</Text>
                  </Box>
                ))}
              </Row>
            </Stack>
          )}

          {step === 2 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Preferences</Heading>
              <Select label="Role" value={formData.role} onChange={(v) => setFormData({ ...formData, role: v })} options={props.roleOptions.map((r) => ({ value: r, label: r }))} />
              <Toggle label="Email Notifications" checked={formData.emailNotifications} onChange={(v) => setFormData({ ...formData, emailNotifications: v })} />
              <RadioGroup label="Theme" value={formData.theme} onChange={(v) => setFormData({ ...formData, theme: v })} options={[{ value: 'light', label: 'Light' }, { value: 'dark', label: 'Dark' }]} />
            </Stack>
          )}

          {step === 3 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Review & Confirm</Heading>
              <Text>Name: {formData.name}</Text>
              <Text>Email: {formData.email}</Text>
              <Text>Role: {formData.role}</Text>
              <Text>Notifications: {formData.emailNotifications ? 'On' : 'Off'}</Text>
              <Text>Theme: {formData.theme}</Text>
              <Text>Avatar: {formData.avatar}</Text>
            </Stack>
          )}
        </Card>

        <Row gap="var(--ggui-spacing-4)" justify="between">
          <Button as={Clickable} variant="ghost" onClick={handleBack} disabled={step === 1}>Back</Button>
          {step < 3 ? (
            <Button as={Clickable} variant="primary" onClick={handleNext} disabled={step === 1 && !isStep1Valid}>Next</Button>
          ) : (
            <Button as={Clickable} variant="primary" onClick={handleSubmit}>Complete Setup</Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}
